class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()
        self.longest_word = ""
        self.max_length = 0

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def find_longest_word(self) -> str:
        self._dfs_longest(self.root, [])
        return self.longest_word

    def _dfs_longest(self, node: TrieNode, current_path_chars: list):
        if node.is_end_of_word:
            current_word = "".join(current_path_chars)
            if len(current_word) > self.max_length:
                self.max_length = len(current_word)
                self.longest_word = current_word

        for char, child_node in node.children.items():
            current_path_chars.append(char)
            self._dfs_longest(child_node, current_path_chars)
            current_path_chars.pop()

